### Python Implementation (Flask/Django)

```python
import redis
import time
from functools import wraps
from flask import request, abort

class RateLimiter:
    def __init__(self, redis_host='localhost', redis_port=6379, db=0):
        self.redis = redis.Redis(
            host=redis_host,
            port=redis_port,
            db=db,
            decode_responses=True
        )

    def is_rate_limited(self, key: str, max_requests: int, window_seconds: int) -> bool:
        """
        Sliding window rate limiting using Redis
        Returns True if rate limit exceeded
        """
        current_time = int(time.time())
        window_key = f"ratelimit:{key}:{current_time // window_seconds}"

        # Get current count
        current_count = self.redis.get(window_key)

        if current_count is None:
            self.redis.setex(window_key, window_seconds, 1)
            return False

        if int(current_count) >= max_requests:
            return True

        self.redis.incr(window_key)
        return False

    def get_remaining(self, key: str, max_requests: int, window_seconds: int) -> int:
        """Get remaining requests in current window"""
        current_time = int(time.time())
        window_key = f"ratelimit:{key}:{current_time // window_seconds}"
        current_count = self.redis.get(window_key)

        if current_count is None:
            return max_requests

        return max(0, max_requests - int(current_count))


# Decorator for API endpoints
def rate_limit(max_requests=100, window_seconds=60):
    limiter = RateLimiter()

    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            # Get client IP
            client_ip = request.headers.get('X-Forwarded-For', request.remote_addr)

            if limiter.is_rate_limited(client_ip, max_requests, window_seconds):
                abort(429, description="Rate limit exceeded")

            return f(*args, **kwargs)
        return wrapped
    return decorator

# Usage
@app.route('/api/endpoint')
@rate_limit(max_requests=100, window_seconds=60)
def api_endpoint():
    return {"status": "success"}
```

### PHP Implementation (Laravel/Symfony)

```php
<?php
class RateLimiter
{
    private Redis $redis;

    public function __construct()
    {
        $this->redis = new Redis();
        $this->redis->connect('127.0.0.1', 6379);
    }

    public function isRateLimited(string $key, int $maxRequests, int $windowSeconds): bool
    {
        $currentTime = time();
        $windowKey = "ratelimit:{$key}:" . floor($currentTime / $windowSeconds);

        $currentCount = $this->redis->get($windowKey);

        if ($currentCount === false) {
            $this->redis->setex($windowKey, $windowSeconds, 1);
            return false;
        }

        if ((int)$currentCount >= $maxRequests) {
            return true;
        }

        $this->redis->incr($windowKey);
        return false;
    }

    public function getRateLimitHeaders(string $key, int $maxRequests, int $windowSeconds): array
    {
        $currentTime = time();
        $windowKey = "ratelimit:{$key}:" . floor($currentTime / $windowSeconds);
        $currentCount = (int)$this->redis->get($windowKey) ?: 0;

        return [
            'X-RateLimit-Limit' => $maxRequests,
            'X-RateLimit-Remaining' => max(0, $maxRequests - $currentCount),
            'X-RateLimit-Reset' => $currentTime + $windowSeconds
        ];
    }
}

// Middleware Example
class RateLimitMiddleware
{
    private RateLimiter $limiter;

    public function __construct()
    {
        $this->limiter = new RateLimiter();
    }

    public function handle($request, $next, $maxRequests = 100, $windowSeconds = 60)
    {
        $clientIp = $request->ip();

        if ($this->limiter->isRateLimited($clientIp, $maxRequests, $windowSeconds)) {
            return response()->json([
                'error' => 'Rate limit exceeded',
                'retry_after' => $windowSeconds
            ], 429);
        }

        $response = $next($request);

        // Add rate limit headers
        $headers = $this->limiter->getRateLimitHeaders($clientIp, $maxRequests, $windowSeconds);
        foreach ($headers as $key => $value) {
            $response->headers->set($key, $value);
        }

        return $response;
    }
}
