class TokenBucketLimiter:
    def __init__(self, redis_host='localhost', redis_port=6379):
        self.redis = redis.Redis(host=redis_host, port=redis_port, decode_responses=True)

    def consume(self, key: str, capacity: int, refill_rate: int, tokens: int = 1) -> bool:
        """
        Token bucket rate limiting
        capacity: max tokens
        refill_rate: tokens per second
        Returns True if request allowed
        """
        bucket_key = f"tokenbucket:{key}"
        last_update_key = f"tokenbucket:{key}:last"

        pipe = self.redis.pipeline()

        # Get current state
        tokens_available = self.redis.get(bucket_key)
        last_update = self.redis.get(last_update_key)

        current_time = time.time()

        if tokens_available is None:
            # Initialize bucket
            tokens_available = capacity
            last_update = current_time
        else:
            tokens_available = float(tokens_available)
            last_update = float(last_update)

            # Refill tokens based on time elapsed
            time_elapsed = current_time - last_update
            tokens_available = min(capacity, tokens_available + (time_elapsed * refill_rate))

        # Consume tokens
        if tokens_available >= tokens:
            tokens_available -= tokens
            pipe.set(bucket_key, tokens_available)
            pipe.set(last_update_key, current_time)
            pipe.expire(bucket_key, 3600)
            pipe.expire(last_update_key, 3600)
            pipe.execute()
            return True

        return False
